import React, { useState } from 'react';

const DATA = {
  India: ['Maharashtra', 'Karnataka', 'Tamil Nadu', 'Gujarat'],
  USA: ['California', 'Texas', 'New York', 'Florida'],
  Germany: ['Bavaria', 'Berlin', 'Hesse', 'Saxony'],
};

export default function CountryState() {
  const [country, setCountry] = useState('');
  const [state, setState] = useState('');

  const states = country ? DATA[country] : [];

  const onCountry = (c) => {
    setCountry(c);
    setState(''); // reset dependent value
  };

  const sel = { padding: 8, fontSize: 15, minWidth: 180 };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12, maxWidth: 200 }}>
      <label>
        Country
        <select value={country} onChange={(e) => onCountry(e.target.value)} style={sel}>
          <option value="">Select…</option>
          {Object.keys(DATA).map((c) => (
            <option key={c} value={c}>{c}</option>
          ))}
        </select>
      </label>

      <label>
        State
        <select value={state} onChange={(e) => setState(e.target.value)} disabled={!country} style={sel}>
          <option value="">{country ? 'Select…' : '— pick a country first —'}</option>
          {states.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
      </label>

      {country && state && (
        <p style={{ color: '#16a34a' }}>Selected: {state}, {country}</p>
      )}
    </div>
  );
}

