import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-country-state',
  template: `
    <div style="display: flex; flex-direction: column; gap: 12px; max-width: 200px;">
      <label>
        Country
        <select [value]="country" (change)="onCountry($any($event.target).value)" style="padding: 8px; font-size: 15px; min-width: 180px;">
          <option value="">Select…</option>
          <option *ngFor="let c of countries" [value]="c">{{ c }}</option>
        </select>
      </label>

      <label>
        State
        <select [value]="state" (change)="state = $any($event.target).value" [disabled]="!country" style="padding: 8px; font-size: 15px; min-width: 180px;">
          <option value="">{{ country ? 'Select…' : '— pick a country first —' }}</option>
          <option *ngFor="let s of states" [value]="s">{{ s }}</option>
        </select>
      </label>

      <p *ngIf="country && state" style="color: #16a34a;">Selected: {{ state }}, {{ country }}</p>
    </div>
  `,
})
export class CountryStateComponent {
  country = '';
  state = '';
  data: Record<string, string[]> = {
    India: ['Maharashtra', 'Karnataka', 'Tamil Nadu', 'Gujarat'],
    USA: ['California', 'Texas', 'New York', 'Florida'],
    Germany: ['Bavaria', 'Berlin', 'Hesse', 'Saxony'],
  };

  get countries(): string[] {
    return Object.keys(this.data);
  }

  get states(): string[] {
    return this.country ? this.data[this.country] : [];
  }

  onCountry(c: string): void {
    this.country = c;
    this.state = '';
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Dependent Dropdowns Demo</h1>
      <app-country-state></app-country-state>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, CountryStateComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
